/**
 * Webapp configuration.
 *
 * This is the single source of truth for the embedding model used in the browser
 * and for the GitHub repository coordinates used to construct data URLs.
 *
 * The model ID here MUST match the default in src/embedding-config.ts so that the
 * pre-computed embeddings (generated by src/prepare-data.ts) and the live query
 * embeddings (computed in-browser) use the same vector space.
 *
 * To change the model:
 *  1. Update MODEL_ID below.
 *  2. Update the default in src/embedding-config.ts accordingly.
 *
 * REPO_OWNER / REPO_NAME identify the GitHub repository that hosts the pre-computed
 * data on the data-main branch.  Forks need to update these two values.
 */
export const MODEL_ID = 'Xenova/paraphrase-mpnet-base-v2';
export const REPO_OWNER = 'huberp';
export const REPO_NAME = 'chromadb-eval';
